INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-001', '연차휴가 신청서', '연차/연차휴가 사용 시 작성', '근태/휴가', '<h1 style="text-align:center;font-size:20px">연 차 휴 가 신 청 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">휴가 종류</th><td>☐ 연차 &nbsp; ☐ 하계휴가 &nbsp; ☐ 경조휴가 &nbsp; ☐ 기타 ( &nbsp; &nbsp; &nbsp; &nbsp; )</td></tr><tr><th>휴가 기간</th><td>&nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ~ &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 (총 &nbsp; &nbsp; 일간)</td></tr><tr><th>잔여 연차</th><td>총 &nbsp; &nbsp; 일 중 &nbsp; &nbsp; 일 사용 / &nbsp; &nbsp; 일 잔여</td></tr><tr><th>휴가 사유</th><td style="height:60px"></td></tr><tr><th>비상연락처</th><td></td></tr><tr><th>업무대행자</th><td>부서: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 성명: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</td></tr></table><p><br></p><p style="text-align:center;font-size:13px">위와 같이 휴가를 신청하오니 허가하여 주시기 바랍니다.</p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-002', '반차 신청서', '오전/오후 반차 사용 시 작성', '근태/휴가', '<h1 style="text-align:center;font-size:20px">반 차 신 청 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">반차 구분</th><td>☐ 오전 반차 (09:00~13:00) &nbsp; ☐ 오후 반차 (14:00~18:00)</td></tr><tr><th>반차 일자</th><td>&nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ( &nbsp; &nbsp; 요일)</td></tr><tr><th>사 유</th><td style="height:60px"></td></tr><tr><th>비상연락처</th><td></td></tr></table><p><br></p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-003', '지각/조퇴/외출 사유서', '지각, 조퇴, 외출 시 사유 기재', '근태/휴가', '<h1 style="text-align:center;font-size:20px">지각 / 조퇴 / 외출 사유서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">구 분</th><td>☐ 지각 &nbsp; ☐ 조퇴 &nbsp; ☐ 외출</td></tr><tr><th>일 시</th><td>&nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 &nbsp; &nbsp; 시 &nbsp; &nbsp; 분 ~ &nbsp; &nbsp; 시 &nbsp; &nbsp; 분</td></tr><tr><th>사 유</th><td style="height:80px"></td></tr><tr><th>증빙서류</th><td>☐ 있음 (첨부) &nbsp; ☐ 없음</td></tr></table><p><br></p><p style="text-align:center;font-size:13px">위와 같은 사유로 보고드리오니 양해하여 주시기 바랍니다.</p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-004', '결근 사유서', '결근 발생 시 사유 기재', '근태/휴가', '<h1 style="text-align:center;font-size:20px">결 근 사 유 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">결근 일자</th><td>&nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ~ &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 (총 &nbsp; &nbsp; 일)</td></tr><tr><th>결근 사유</th><td style="height:100px"></td></tr><tr><th>증빙서류</th><td>☐ 진단서 &nbsp; ☐ 기타 ( &nbsp; &nbsp; &nbsp; &nbsp; ) &nbsp; ☐ 없음</td></tr><tr><th>향후 계획</th><td style="height:60px"></td></tr></table><p><br></p><p style="text-align:center;font-size:13px">위와 같은 사유로 결근하였기에 사유서를 제출합니다.</p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-005', '휴직 신청서', '육아휴직, 병가휴직 등 휴직 시 작성', '근태/휴가', '<h1 style="text-align:center;font-size:20px">휴 직 신 청 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr><tr><th>입사일</th><td></td><th>연락처</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">휴직 유형</th><td>☐ 육아휴직 &nbsp; ☐ 병가휴직 &nbsp; ☐ 개인사유 &nbsp; ☐ 기타 ( &nbsp; &nbsp; &nbsp; )</td></tr><tr><th>휴직 기간</th><td>&nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ~ &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 (총 &nbsp; &nbsp; 개월)</td></tr><tr><th>휴직 사유</th><td style="height:80px"></td></tr><tr><th>첨부 서류</th><td>☐ 진단서 &nbsp; ☐ 출생증명서 &nbsp; ☐ 기타 ( &nbsp; &nbsp; &nbsp; &nbsp; )</td></tr><tr><th>업무인수자</th><td>부서: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 성명: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</td></tr></table><p><br></p><p style="text-align:center;font-size:13px">위와 같이 휴직을 신청하오니 승인하여 주시기 바랍니다.</p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-006', '복직 신청서', '휴직 후 복직 시 작성', '근태/휴가', '<h1 style="text-align:center;font-size:20px">복 직 신 청 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">휴직 기간</th><td>&nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ~ &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일</td></tr><tr><th>휴직 유형</th><td></td></tr><tr><th>복직 예정일</th><td>&nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</td></tr><tr><th>복직 사유</th><td style="height:60px"></td></tr><tr><th>건강 상태</th><td>☐ 양호 &nbsp; ☐ 치료 중 (상세: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; )</td></tr></table><p><br></p><p style="text-align:center;font-size:13px">위와 같이 복직을 신청하오니 승인하여 주시기 바랍니다.</p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-007', '출장 신청서', '국내/해외 출장 시 사전 승인용', '근태/휴가', '<h1 style="text-align:center;font-size:20px">출 장 신 청 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">출장 구분</th><td>☐ 국내 출장 &nbsp; ☐ 해외 출장</td></tr><tr><th>출장 기간</th><td>&nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ~ &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ( &nbsp; 박 &nbsp; 일)</td></tr><tr><th>출장지</th><td></td></tr><tr><th>출장 목적</th><td style="height:60px"></td></tr><tr><th>동행자</th><td></td></tr><tr><th>예상 경비</th><td>교통비: &nbsp; &nbsp; &nbsp; &nbsp; 원 / 숙박비: &nbsp; &nbsp; &nbsp; &nbsp; 원 / 기타: &nbsp; &nbsp; &nbsp; &nbsp; 원 / 합계: &nbsp; &nbsp; &nbsp; &nbsp; 원</td></tr><tr><th>업무대행자</th><td></td></tr></table><p><br></p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-008', '출장 보고서', '출장 완료 후 결과 보고', '근태/휴가', '<h1 style="text-align:center;font-size:20px">출 장 보 고 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>출장 기간</th><td colspan="3">&nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ~ &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일</td></tr><tr><th>출장지</th><td></td><th>출장 목적</th><td></td></tr></table><p><br></p><h2 style="font-size:15px">출장 내용</h2><table><tr><th style="width:15%">일자</th><th style="width:25%">방문처</th><th style="width:60%">주요 활동 내용</th></tr><tr><td></td><td></td><td style="height:40px"></td></tr><tr><td></td><td></td><td style="height:40px"></td></tr></table><p><br></p><h2 style="font-size:15px">출장 성과 및 결과</h2><p style="min-height:60px"><br></p><h2 style="font-size:15px">후속 조치 사항</h2><p style="min-height:60px"><br></p><h2 style="font-size:15px">경비 정산</h2><table><tr><th>항목</th><th>금액</th><th>비고</th></tr><tr><td>교통비</td><td></td><td></td></tr><tr><td>숙박비</td><td></td><td></td></tr><tr><td>식비</td><td></td><td></td></tr><tr><td>기타</td><td></td><td></td></tr><tr><td><strong>합계</strong></td><td></td><td></td></tr></table><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-009', '재택근무 신청서', '재택근무 사전 승인용', '근태/휴가', '<h1 style="text-align:center;font-size:20px">재택근무 신청서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">근무 일자</th><td>&nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ( &nbsp; &nbsp; 요일)</td></tr><tr><th>근무 시간</th><td>&nbsp; &nbsp; 시 &nbsp; &nbsp; 분 ~ &nbsp; &nbsp; 시 &nbsp; &nbsp; 분</td></tr><tr><th>근무 장소</th><td>☐ 자택 &nbsp; ☐ 기타 ( &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; )</td></tr><tr><th>신청 사유</th><td style="height:60px"></td></tr><tr><th>업무 계획</th><td style="height:80px"></td></tr><tr><th>연락 수단</th><td>전화: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; / 메신저: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</td></tr></table><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p>', 'admin-001', 1);
INSERT INTO templates (id, title, description, category, content, created_by, is_active) VALUES
